var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"큭……! 굉장한 실력이군!","JPN":"くっ……！　凄まじい実力だな。","ENG":"Ugh…! Impressive!","TWN":"唔……！果然厲害！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하! 봤지? 이것이야말로 블루스틸 삼검류의 위력!","JPN":"ふっ、わかったでしょ？　これこそがブルースチール三剣流の威力よ！","ENG":"Ha! Did you see that? That's the power of the Bluesteel Three-Sword technique!","TWN":"哈！看到了吧！這就是布魯斯提爾三刀流的厲害！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"칼 두 개는 뽑지도 않았으면서 뭐가 삼검류야?","JPN":"剣は一本しか使ってないくせに何が三剣流なの？","ENG":"Three-Sword Technique? You only used one sword!","TWN":"你只有拔一把刀出來，哪來的三刀流？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"애초에 저쪽 대장은 내가 상대했잖아.","JPN":"そもそも、あの隊長の相手は私がしたんだけど？","ENG":"Besides, I'm the one who fought their captain.","TWN":"而且那個隊長從一開始就在和我對打好嗎？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"펴, 편입생 주제에 시끄러워!","JPN":"へ、編入生のくせにうるさいわよ！","ENG":"S-shut up, transfer student!","TWN":"插…插班生你別吵！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"대장님! 괜찮으십니까?","JPN":"隊長！　大丈夫ですか！？","ENG":"Captain! How fairest thee?","TWN":"隊長！你沒事吧？"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그래, 아직은 싸울 수 있다.","JPN":"ああ、まだ戦える。","ENG":"Well enough to keep fighting.","TWN":"我沒事，我還能繼續戰鬥！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"전령을 보내라. 성녀님께 상황을 알려야 한다.","JPN":"伝令を送れ。聖女様に状況を知らせねば。","ENG":"Send the messenger. We must inform the Saintess presently.","TWN":"傳令！必須將情況報告給聖女知道！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"알겠습니다!","JPN":"承知しました！","ENG":"Understood!","TWN":"是，遵命！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"네. 죄송하지만 이 길은 잠시 통행금지랍니다.","JPN":"はい、申し訳ありませんがこの道はしばらく通行止めになりまーす。","ENG":"That's right. Sorry, but this path is blocked for now.","TWN":"好不意思，此路不通喔！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"이런! 뒤에도 적이……!","JPN":"しまった！　後ろにも敵が……！","ENG":"Alas! The enemy has taken the rear!","TWN":"可惡！後面也有埋伏……！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"요즘은 이런 역할을 자주 맡네.","JPN":"最近はこういう役割が多いなあ。","ENG":"I'm always playing the bad guy these days, huh.","TWN":"我最近很常扮演這種角色呢！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"이미지 쇄신도 해야 할 텐데 곤란하다니까, 정말.","JPN":"イメージ向上もしなきゃだし、困ったわ。まったく……","ENG":"This really isn't helping with my image.","TWN":"要改變一下形象，不然會被定型。"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"당장 물러서라! 그렇지 않으면 베겠다!","JPN":"退け！　さもなくば斬るぞ！","ENG":"Step aside, fiend! Else, I shall cut thee down!","TWN":"走開！否則我要出手囉！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"아, 그건 다시 생각해 보는 편이 좋을 거예요.","JPN":"あ、それは考え直してもらったほうがいいですね。","ENG":"Oh, you might want to rethink that.","TWN":"哦～我勸你還是打消這個念頭吧！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"당신들, 이미 포위된 상태거든요.","JPN":"あなたたち、すでに包囲されてますよ？","ENG":"You're all already surrounded, you see.","TWN":"你們已經被包圍囉！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭣이?!","JPN":"な、なんだと！？","ENG":"W-what?!","TWN":"什…什麼？！"},"stage":{"bg":"CASTLE_01","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 나이엘은 빼고.","JPN":"いや、ナイエル以外でね。","ENG":"Um, let's leave Naielle out of this.","TWN":"不，不包括奈爾。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 그 편이 좋겠어요.","JPN":"はい、その方がよさそうです。","ENG":"Agreed. That would be wise.","TWN":"嗯，這樣比較好。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"무, 무슨 뜻이야! 그거!","JPN":"ど、どういう意味よ！？","ENG":"W-what? Why?!","TWN":"什…這是什麼意思嘛！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"……좋다. 패배를 인정하지.","JPN":"……わかった。敗北を認める。","ENG":"...Very well. I concede defeat.","TWN":"……好吧，我認輸了。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"뭘 원하는지는 모르겠지만 최대한 협조하겠다. 대신 부하들의 안전은 보장해 다오.","JPN":"何が望みなのかはわからないが、最大限協力する。代わりに部下の安全は保障してくれ。","ENG":"I know not what you desire, but you shall have my full cooperation. However, do guarantee my men's safety.","TWN":"雖然我不清楚你們的目的是什麼，但我會盡量協助你們，不過你們必須保證不會傷害我的手下！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"안심하세요. 처음부터 해칠 생각은 없었어요.","JPN":"安心してください。最初から危害を加えるつもりはありませんでした。","ENG":"Don't worry about that. We never meant to hurt you anyway.","TWN":"不用擔心，我們從一開始就沒有要傷人的意思。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"크흠, 그러고 보면……. 나와 겨룬 소녀도 부상을 입히지 않았지.","JPN":"ふむ、そういえば……私と決闘した少女も負傷を負わせないような動きだった。","ENG":"Ahem… Come to think of it… The lass who fought me left me no injuries.","TWN":"話說……和我交手的那個女孩應該也沒受傷吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"정확히 보셨어요. 저희가 원하는 건 약간의 정보뿐이에요.","JPN":"そのとおりです。私たちが求めるのは、少しの情報だけです。","ENG":"Exactly. All we want is a little bit of information.","TWN":"沒錯，我們只是想要打聽一些事而已。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"질문에 대답해 주시면, 귀하는 물론 다른 분들도 무사히 보내 드리겠어요.","JPN":"質問に答えてくださるなら、あなたはもちろん他の方も無事にお送りします。","ENG":"If you can answer our question, we'll release all of you unharmed.","TWN":"你回答完後，你和你的手下們都可以平安離開。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"의심은 거둘 수 없다만……. 선택의 여지도 없군.","JPN":"疑いは晴れていないが……選択の余地もないか。","ENG":"Though the clouds of suspicion still loom about me… I have no choice, methinks.","TWN":"雖然有點懷疑……但我也沒有選擇的餘地。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"좋다. 무엇이 궁금하지?","JPN":"いいだろう。何が知りたいんだ？","ENG":"Very well. How may I satiate thy curiosity?","TWN":"說吧！你們想知道什麼？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아르카데나 제국이란 무엇인지 듣고 싶군요.","JPN":"アルカデナ帝国とはどういった国なのか知りたいです。","ENG":"For starters, we'd like to know more about this Empire of Arcadena.","TWN":"我們想了解一下艾爾卡特納帝國，"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 여러분이 말한 <color=#ffd34c>마왕</color>에 대해서도.","JPN":"そして皆さんがおっしゃっていた<color=#ffd34c>魔王</color>についても。","ENG":"And also about the <color=#ffd34c>Demon Lord</color> you mentioned.","TWN":"還有各位口裡說的那位<color=#ffd34c>魔王</color>。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"마왕에 대해서? 정말 아무것도 모르나 보군. ","JPN":"魔王について？　本当に何も知らないようだな。","ENG":"The Demon Lord? So you truly know nothing at all. ","TWN":"魔王？原來你們真的什麼都不知道。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"아르카데나 제국은 이곳 중앙 대륙에서 가장 오래된 국가다.","JPN":"アルカデナ帝国は中央大陸で最も古くから続く国だ。","ENG":"The Empire of Arcadena is the oldest nation in this Central Continent.","TWN":"艾爾卡特納帝國是中央大陸這裡歷史最悠久的國家。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"다섯 연방국과 세 공국으로부터 충성 서약을 받은 인류 최강의 대제국이지.","JPN":"5つの連邦国と3つの公国から忠誠誓約を受けた、人類最強の大帝国である。","ENG":"It was once the most powerful empire known to Man, with five federations and three duchies swearing vassalage.","TWN":"有5個聯邦國家和3個公國都簽訂契約要效忠於我們，我們可以說是當時人類最強的帝國。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"지금은…… 모두 옛날 이야기가 되어 버렸지만.","JPN":"今は……すべて昔の話になってしまったが。","ENG":"Though of course… That's all in the past now.","TWN":"雖然……這些都已經是過去的事了。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 뜻이야? 당신들이 여기 있는 걸 보면 나라가 망한 것도 아닐 텐데?","JPN":"どういうこと？　あなたたちがここにいるってことは、国が滅びたわけでもないでしょ？","ENG":"What do you mean? If you're still here, I'm guessing your country's still around, no?","TWN":"什麼意思？你們不是還在這裡嗎？應該就表示國家還沒滅亡吧？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"연방국도, 공국도, 바다 저편의 다른 나라들도 모두 멸망해 버렸으니까.","JPN":"連邦国も公国も、海の向こうの他の国々も、すべて滅びてしまったからだ。","ENG":"But alas, the federations, duchies, and even the kingdoms across the seas have all fallen.","TWN":"因為無論是聯邦國家，還是公國，或是大海那邊的國家全都滅亡了。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"인류의 마지막 국가가 된 지금은 최강이니 최고니 아무런 의미도 없지.","JPN":"人類最後の国家になった今、最強も最高も何の意味もない。","ENG":"As the final nation of Man, no title of grandeur bears meaning now.","TWN":"我們現在是人類最後的國家，說什麼最強、最厲害，又有什麼意義呢？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다른 나라들이…… 모두 망해 버렸다고?","JPN":"他の国が……すべて滅びたの？","ENG":"All the other countries… are gone?","TWN":"其他國家……全都滅亡了？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"귀하가 말했던, 그 마왕이란 자 때문인가요?","JPN":"あなたがおっしゃった、魔王という者のせいですか？","ENG":"Is it because of that Demon Lord you spoke of?","TWN":"是因為你們說個那個魔王嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그래. 몇 년 전 여덟 대륙을 모두 불태운 마왕, <color=#ffd34c>속삭이는 자</color>가 서쪽 해안에 상륙했다.","JPN":"そうだ。数年前、八つの大陸を燃やし尽くした魔王、<color=#ffd34c>囁く者</color>が西海岸に上陸した。","ENG":"Aye. Several years ago, the Demon Lord known as <color=#ffd34c>the Whisperer</color> landed on our western shore after scorching the other eight continents.","TWN":"沒錯，幾年前魔王燒毀8個大陸，<color=#ffd34c>不能說的人</color>從西海岸登陸。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"제국도 모든 힘을 동원해 맞섰지만, 이미 영토의 절반이 불타 버렸지.","JPN":"帝国も力を総動員して対抗したが、すでに領土の半分が焦土と化した。","ENG":"Though the Empire fought with all its might, half of our territory had already burned to the ground.","TWN":"帝國雖然也有出動所有的力量迎擊，但一大半的領土早就陷入一片火海。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"이제 사람이 살 수 있는 땅은 센트럴 팰리스 일대뿐이다.","JPN":"今や人が住める土地はセントラルパレス一帯のみだ。","ENG":"Central Palace remains the sole inhabitable land now.","TWN":"現在人類可以居住的土地就只剩聖特羅貝里斯這裡而已。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설정 같은 건…… 아니겠지.","JPN":"設定みたいな……ものではないよね。","ENG":"This isn't some theme park backstory, is it?","TWN":"你不是在……說故事吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 받아들이기는 어렵지만, 이 분이 거짓말을 하는 것 같지는 않아요.","JPN":"はい。受け入れがたいですが、この方が嘘をついているようには見えませんね。","ENG":"I fear not. As difficult as it is to believe, I don't think he is lying.","TWN":"雖然有點難以置信，但他不像是在說謊的樣子。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래. 저 도시도 가짜 같지는 않아.","JPN":"うん。あの都市も偽物には見えない。","ENG":"Right. That city doesn't look fake either.","TWN":"也是，那個城市也不像假的。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"당신이 말한 대로라면 희망이 없다는 뜻이잖아.","JPN":"あなたの話どおりだと、希望がないってことじゃない。","ENG":"If what you said is true, that means things are pretty hopeless.","TWN":"如果照你說的，根本一點希望也沒有吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기서 얌전히 있지 말고 도망이라도 쳐야 하는 거 아냐?","JPN":"ここでおとなしくしているよりも、逃げるべきなんじゃない？","ENG":"Shouldn't you guys run away or something? Why stay here?","TWN":"什麼安分地待在這裡，根本該立刻逃離吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"어차피 마왕의 진격을 막지 않는 한, 도망갈 곳은 없다.","JPN":"どうせ魔王の進撃を止められない限り、逃げ場はない。","ENG":"There is nowhere left to flee, unless the Demon Lord's advances can be stopped.","TWN":"只要一天不阻止魔王，你是能逃到哪裡去呢？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그리고 우리에게도 희망은 아직 남아 있어.","JPN":"そして我々には希望がまだ残っている。","ENG":"And we do have one last source of hope.","TWN":"更何況我們還沒放棄希望！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"<color=#ffd34c>구원기사단</color>이 있는 한에는.","JPN":"<color=#ffd34c>救世騎士団</color>がいる限り。","ENG":"So long as the <color=#ffd34c>Knights of Redemption</color> exist.","TWN":"只要<color=#ffd34c>救贖騎士團</color>在！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"구원기사단……?","JPN":"救世騎士団……？","ENG":"Knights of Redemption…?","TWN":"救贖騎士團……？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그래! 국적도 신분도 구분없이 아홉 대륙 최고의 실력자들만을 모은 기사단이지!","JPN":"そうだ！　国籍も身分も関係ない、九つの大陸の最高実力者だけを集めた騎士団だ！","ENG":"Aye! 'Tis an order of the most capable knights, hailing from all nine continents, of all nations, creeds, or classes!","TWN":"對！這個騎士團裡面不分國籍或是身分，成員裡全是9個大陸中最厲害的高手！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"역사상 몇 차례나 인류를 구한 그들이 마왕과의 일전을 준비 중이다.","JPN":"歴史上、何度も人類を救った彼らが魔王との一戦を準備している。","ENG":"They've already saved civilization several times throughout history. And now, they prepare for one final battle with the Demon Lord.","TWN":"他們在歷史上曾經拯救過人類幾次，現在他們正準備要和魔王決一死戰。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"이번 세대에는 이백 년만에 처음으로 <color=#ffd34c>구원자의 제복</color>을 계승한 분도 계신다더군.","JPN":"この世代には200年ぶりに初めて<color=#ffd34c>救世主の礼装</color>を継承した方もいらっしゃるそうだ。","ENG":"And in this generation, there's even someone who had inherited the <color=#ffd34c>Uniform of the Savior</color>.","TWN":"而且這次200年來首次繼承<color=#ffd34c>救贖者戰甲</color>的人也在當中！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"게다가 역대 황실 최강의 검사인 황태자 전하에, 부활의 성녀 루크레시아님까지 기사단에 합류하셨다.","JPN":"さらに、歴代皇室最強の剣士である皇太子殿下に、復活の聖女ルクレシア様まで騎士団に合流された。","ENG":"Moreover, the order is joined by our honorable Crown Prince, the most capable swordsman of the crown, and Lucrecia, the Saintess of Resurrection.","TWN":"還有皇室史上最傑出的劍士 皇太子殿下，以及復活的聖女 露可蕾西亞都加入了騎士團！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그 분들이라면……. 분명 이 전쟁에서 이길 수 있다.","JPN":"あの方々なら……必ずこの戦いに勝てる。","ENG":"So long as they are with us… We shall win this war.","TWN":"我相信只要有他們……一定可以打贏這場戰的！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그리고 얼마 전 마왕의 사도를 격퇴했다던 <color=#ffd34c>펜릴 용병대</color> 놈들도, 나름 도움이 되겠지.","JPN":"そして先日、魔王の使徒を撃退したという<color=#ffd34c>フェンリル傭兵隊</color>の連中も、それなりに役に立つだろう。","ENG":"And those <color=#ffd34c>Fenrir Mercenaries</color> who bested the Apostles of the Demon Lord recently might also be of some help.","TWN":"而且不久前曾經擊退魔王手下的<color=#ffd34c>芬里爾傭兵隊</color>應該也可以幫上忙吧？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 용병대?","JPN":"フェンリル傭兵隊？","ENG":"Fenrir Mercenaries?","TWN":"芬里爾傭兵隊？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"……재미있네.","JPN":"……面白いね。","ENG":"…Now this is getting interesting.","TWN":"……真有意思。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"그러고 보니…… 너희들의 복식과 무기는 그 용병대 놈들 것과 비슷하군.","JPN":"そういえば……君たちの服飾と武器はあの傭兵隊のものと似ているな。","ENG":"Come to think of it… Your liveries and arms are rather akin to that of those mercenaries.","TWN":"話說回來……我看你們的穿著和武器，和那些傭兵隊的傢伙很像呢！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"혹시 펜릴 용병대와 한 패인가?","JPN":"もしかしてフェンリル傭兵隊の仲間か？","ENG":"Are you with the Fenrir Mercenaries?","TWN":"你們和芬里爾傭兵隊是一掛的嗎？"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"Well…","TWN":"這個嘛……"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"……대답하실 필요 없습니다.","JPN":"……お答えする必要はございません。","ENG":"There's no need to answer that.","TWN":"……你不需要回答。"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"자세한 것은 제가 말씀드리죠. 당신들은 제 손님이니까요.","JPN":"詳しいことは私から伝えます。あなた方は私のお客様ですから。","ENG":"I will tell you all the details. You are my guests, after all.","TWN":"就由我來代為回答吧，畢竟你們是我的客人！"},"stage":{"bg":"CASTLE_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};